import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';

// Layout Components
import Layout from './components/Layout';

// Auth Components
import Login from './pages/auth/Login';
import Register from './pages/auth/Register';
import EmailVerification from './pages/auth/EmailVerification';

// Dashboard Components
import UserDashboard from './pages/dashboard/UserDashboard';
import AdminDashboard from './pages/dashboard/AdminDashboard';
import WorkerDashboard from './pages/dashboard/WorkerDashboard';
import OwnerDashboard from './pages/dashboard/OwnerDashboard';

// Complaint Components
import ComplaintList from './pages/complaints/ComplaintList';
import CreateComplaint from './pages/complaints/CreateComplaint';
import ComplaintDetail from './pages/complaints/ComplaintDetail';

// User Management Components
import UserManagement from './pages/admin/UserManagement';
import CreateUser from './pages/admin/CreateUser';

// Profile Component
import Profile from './pages/Profile';

function App() {
  return (
    <AuthProvider>
      <Router>
        <div className="App">
          <Routes>
            {/* Public Routes */}
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/verify-email" element={<EmailVerification />} />

            {/* Protected Routes */}
            <Route path="/" element={
              <ProtectedRoute>
                <Layout />
              </ProtectedRoute>
            }>
              <Route index element={<Navigate to="/dashboard" replace />} />

              {/* Dashboard Routes */}
              <Route path="dashboard" element={<RoleBasedDashboard />} />

              {/* Complaint Routes */}
              <Route path="complaints" element={<ComplaintList />} />
              <Route path="complaints/new" element={<CreateComplaint />} />
              <Route path="complaints/:id" element={<ComplaintDetail />} />

              {/* Profile Route */}
              <Route path="profile" element={<Profile />} />

              {/* Admin Routes */}
              <Route path="admin/users" element={<ProtectedRoute roles={['ADMIN', 'OWNER']}><UserManagement /></ProtectedRoute>} />
              <Route path="admin/users/new" element={<ProtectedRoute roles={['ADMIN', 'OWNER']}><CreateUser /></ProtectedRoute>} />
            </Route>

            {/* Catch all route */}
            <Route path="*" element={<Navigate to="/dashboard" replace />} />
          </Routes>

          <Toaster
            position="top-right"
            toastOptions={{
              duration: 4000,
              style: {
                background: '#363636',
                color: '#fff',
              },
              success: {
                duration: 3000,
                iconTheme: {
                  primary: '#22c55e',
                  secondary: '#fff',
                },
              },
              error: {
                duration: 5000,
                iconTheme: {
                  primary: '#ef4444',
                  secondary: '#fff',
                },
              },
            }}
          />
        </div>
      </Router>
    </AuthProvider>
  );
}

// Role-based dashboard component
function RoleBasedDashboard() {
  const { user } = useAuth();

  switch (user?.role) {
    case 'OWNER':
      return <OwnerDashboard />;
    case 'ADMIN':
      return <AdminDashboard />;
    case 'WORKER':
      return <WorkerDashboard />;
    case 'USER':
    default:
      return <UserDashboard />;
  }
}

export default App;
